import React, { useState } from "react";
import "../styles/News.css";

const articles = [
  {
    id: 1,
    title:
      "LENIENCY IN CRIMINAL SENTENCE FOR JUSTICE COLLABORATORS WHO SUPPORTS LAW ENFORCEMENT AUTHORITIES BY UNCOVERING CRIMINAL CASES",
    date: "06 February, 2025",
    image: "/images/news1.jpg",
    description:
      "The key to a successful criminal law enforcement depends on the evidence that has been...",
    fullText:
      "Full article content goes here. This is the detailed explanation...",
  },
  {
    id: 2,
    title:
      "PROTECTION OF OPEN-SOURCE SOFTWARE FROM A COPYRIGHT PERSPECTIVE IN INDONESIA",
    date: "06 February, 2025",
    image: "/images/news2.jpg",
    description:
      "How is open source regulated in copyright law in Indonesia? Despite its nature...",
    fullText:
      "Full article content goes here. This is the detailed explanation...",
  },
  {
    id: 3,
    title:
      "PROTECTION OF OPEN-SOURCE SOFTWARE FROM A COPYRIGHT PERSPECTIVE IN INDONESIA",
    date: "06 February, 2025",
    image: "/images/news3.jpg",
    description:
      "How is open source regulated in copyright law in Indonesia? Despite its nature...",
    fullText:
      "Full article content goes here. This is the detailed explanation...",
  },
];

const News = () => {
  const [selectedArticle, setSelectedArticle] = useState(null);

  // Function to open modal
  const openModal = (article) => {
    setSelectedArticle(article);
  };

  // Function to close modal
  const closeModal = () => {
    setSelectedArticle(null);
  };

  return (
    <div className="News">
      <h2>News & Articles</h2>
      <div className="news-container">
        {articles.map((article) => (
          <div className="news-card" key={article.id}>
            <img src={article.image} alt={article.title} className="news-image" />
            <div className="news-content">
              <h3>{article.title}</h3>
              <p className="news-date">📅 {article.date}</p>
              <p className="news-description">{article.description}</p>
              <div className="button-container">
                <button className="news-button" onClick={() => openModal(article)}>
                  Read More
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Modal */}
      {selectedArticle && (
        <div className="modal-overlay" onClick={closeModal}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button className="close-button" onClick={closeModal}>
              ✖
            </button>
            <h2>{selectedArticle.title}</h2>
            <p className="news-date">📅 {selectedArticle.date}</p>
            <img src={selectedArticle.image} alt={selectedArticle.title} className="news-modal-image" />
            <p className="news-full-text">{selectedArticle.fullText}</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default News;
